INSERT INTO global_rules (layer, rule_type, rule_json, pattern, action, confidence, source, is_active) VALUES (1, 'tds_section', '{"section":"194H","description":"Commission or brokerage","rate":5,"threshold":15000}', '{"section":"194H","description":"Commission or brokerage","keywords":["commission","brokerage","broker","agent","referral fee","dealership","franchise"]}', '{"rate":5,"threshold_inr":15000,"notes":"5% on commission or brokerage payments"}', 1.0, 'Income Tax Act 1961 S.194H', true), (1, 'tds_section', '{"section":"194A","description":"Interest other than on securities","rate":10,"threshold":5000}', '{"section":"194A","description":"Interest other than on securities","keywords":["interest","fd interest","fixed deposit","ncd interest","deposit interest","loan interest"]}', '{"rate":10,"threshold_bank":40000,"threshold_other":5000,"notes":"Bank 40k threshold, others 5k"}', 1.0, 'Income Tax Act 1961 S.194A', true), (1, 'tds_section', '{"section":"194O","description":"E-commerce operator payments","rate":1,"threshold":500000}', '{"section":"194O","description":"E-commerce operator payments","keywords":["amazon","flipkart","zomato","swiggy","meesho","myntra","snapdeal","ecommerce"]}', '{"rate":1,"threshold_inr":500000,"notes":"1% on gross sale via e-commerce platform"}', 1.0, 'Income Tax Act 1961 S.194O', true) ON CONFLICT DO NOTHING;
